head.b:skin:
/*------------------------------------------------------------
PREMIUM PRO NEWS GRADIENT VARIABLE SYSTEM (hadoti-news 2026)
------------------------------------------------------------*/
:root {
    --primary-gradient: linear-gradient(135deg, #ff1e56 0%, #ffac41 50%, #3232ff 100%);
    --neon-glow: 0 0 20px rgba(255, 30, 86, 0.25);
    --dark-bg: #030712;
    --dark-card: #0f172a;
    --light-bg: #f8fafc;
    --light-card: #ffffff;
    --text-main: #0f172a;
    --text-muted: #475569;
    --accent-color: #ff1e56;
    --font-global: 'Plus Jakarta Sans', 'Noto Sans Devanagari', sans-serif;
    --radius-mega: 16px;
    --shadow-mega: 0 20px 40px rgba(15, 23, 42, 0.04);
    --transition: all 0.4s cubic-bezier(0.16, 1, 0.3, 1);
}

body.dark-mode {
    --light-bg: var(--dark-bg);
    --light-card: var(--dark-card);
    --text-main: #f1f5f9;
    --text-muted: #94a3b8;
    --shadow-mega: 0 25px 60px rgba(0, 0, 0, 0.45);
}

/* Structural Framework Base */
* { box-sizing: border-box; margin: 0; padding: 0; }
body { font-family: var(--font-global); background-color: var(--light-bg); color: var(--text-main); transition: var(--transition); overflow-x: hidden; }
a { color: inherit; text-decoration: none; transition: var(--transition); }
img { max-width: 100%; height: auto; display: block; border-radius: 12px; }

#progress-bar { position: fixed; top: 0; left: 0; width: 0%; height: 5px; background: var(--primary-gradient); z-index: 100000; }
.container { max-width: 1320px; margin: 0 auto; padding: 0 24px; }

/* Live Flash Breaking Ticker Module */
.top-bar { background: #090d16; color: #fff; padding: 14px 0; font-size: 13px; border-bottom: 1px solid rgba(255,255,255,0.06); }
.ticker-wrap { display: flex; align-items: center; justify-content: space-between; gap: 20px; }
.ticker-box { display: flex; align-items: center; overflow: hidden; width: 85%; }
.ticker-title { background: var(--primary-gradient); padding: 6px 16px; font-weight: 900; border-radius: 8px; margin-right: 20px; white-space: nowrap; font-size: 12px; letter-spacing: 0.5px; box-shadow: var(--neon-glow); }
.ticker-content { display: inline-block; white-space: nowrap; animation: ticker-live 25s linear infinite; color: #e2e8f0; font-weight: 700; }
@keyframes ticker-live { 0% { transform: translate3d(100%, 0, 0); } 100% { transform: translate3d(-100%, 0, 0); } }

/*------------------------------------------------------------
MEGA BRANDING ATTRACTIVE HEADER LOGO DESIGN
------------------------------------------------------------*/
header { background: rgba(255, 255, 255, 0.85); backdrop-filter: blur(20px); -webkit-backdrop-filter: blur(20px); position: sticky; top: 0; z-index: 9999; box-shadow: 0 4px 30px rgba(0,0,0,0.02); border-bottom: 1px solid rgba(0,0,0,0.05); padding: 18px 0; }
body.dark-mode header { background: rgba(15, 23, 42, 0.85); border-bottom: 1px solid rgba(255,255,255,0.06); }
.header-inner { display: flex; flex-direction: column; align-items: center; gap: 24px; }
@media(min-width: 768px) { .header-inner { flex-direction: row; justify-content: space-between; } }

/* Luxury Glow Decorative Logo */
.logo-branding { position: relative; padding: 8px 24px; text-align: center; background: rgba(255, 30, 86, 0.03); border-radius: 14px; border: 1px solid rgba(255, 30, 86, 0.08); }
.logo-branding h1 { font-size: 44px; font-weight: 900; background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; letter-spacing: -2px; text-transform: uppercase; line-height: 1.1; filter: drop-shadow(0 2px 8px rgba(255,30,86,0.15)); }
.logo-sub { display: block; font-size: 11px; font-weight: 900; color: var(--text-muted); letter-spacing: 5px; text-transform: uppercase; margin-top: 4px; }

nav ul { display: flex; list-style: none; gap: 30px; flex-wrap: wrap; justify-content: center; }
nav ul li a { font-weight: 800; font-size: 15.5px; color: var(--text-main); padding: 8px 0; position: relative; display: flex; align-items: center; gap: 6px; }
nav ul li a::after { content: ''; position: absolute; bottom: 0; left: 0; width: 0; height: 4px; background: var(--primary-gradient); transition: var(--transition); border-radius: 4px; }
nav ul li a:hover::after { width: 100%; }

.nav-actions { display: flex; align-items: center; gap: 15px; }
.mode-btn { width: 44px; height: 44px; border-radius: 12px; background: var(--light-bg); display: flex; align-items: center; justify-content: center; cursor: pointer; border: 1px solid rgba(0,0,0,0.05); transition: var(--transition); color: var(--text-main); }
.mode-btn:hover { background: var(--primary-gradient); color: #fff; transform: translateY(-3px) rotate(12deg); }

/* Structural Core Workspace Layout Layout */
.main-wrapper { display: grid; grid-template-columns: 1fr; gap: 40px; margin-top: 45px; }
@media(min-width: 992px) { .main-wrapper { grid-template-columns: 2.35fr 1fr; } }

/* Multiple Grid Posts CSS */
.posts-grid { display: grid; grid-template-columns: 1fr; gap: 30px; }
@media(min-width: 650px) { .posts-grid { grid-template-columns: 1fr 1fr; } }

.card { background: var(--light-card); border-radius: var(--radius-mega); overflow: hidden; box-shadow: var(--shadow-mega); border: 1px solid rgba(0,0,0,0.03); display: flex; flex-direction: column; height: 100%; transition: var(--transition); }
.card:hover { transform: translateY(-8px); box-shadow: 0 30px 60px rgba(255, 30, 86, 0.12); border-color: rgba(255, 30, 86, 0.2); }
.card-thumb { height: 235px; background: #0f172a; position: relative; overflow: hidden; }
.card-thumb img { width: 100%; height: 100%; object-fit: cover; transition: var(--transition); }
.card:hover .card-thumb img { transform: scale(1.07); }

.badge { position: absolute; top: 15px; left: 15px; background: var(--primary-gradient); color: #fff; padding: 6px 14px; font-size: 11px; font-weight: 900; border-radius: 8px; box-shadow: var(--neon-glow); text-transform: uppercase; }
.card-content { padding: 26px; flex-grow: 1; display: flex; flex-direction: column; justify-content: space-between; }
.card-meta { font-size: 13px; color: var(--text-muted); margin-bottom: 12px; display: flex; gap: 14px; font-weight: 700; }
.card-meta i { color: var(--accent-color); }
.card-title { font-size: 21px; font-weight: 800; line-height: 1.4; margin-bottom: 12px; color: var(--text-main); }
.card-text { font-size: 14px; color: var(--text-muted); line-height: 1.6; margin-bottom: 20px; }
.read-btn { font-weight: 800; font-size: 14px; color: var(--accent-color); display: inline-flex; align-items: center; gap: 8px; }

/* Single Post Full Details View Layout CSS */
.post-body-container { background: var(--light-card); padding: 40px; border-radius: var(--radius-mega); box-shadow: var(--shadow-mega); border: 1px solid rgba(0,0,0,0.03); }
.post-main-title { font-size: 36px; font-weight: 900; line-height: 1.3; margin-bottom: 22px; color: var(--text-main); letter-spacing: -0.5px; }
.breadcrumb-nav { display: flex; gap: 8px; font-size: 13.5px; color: var(--text-muted); margin-bottom: 25px; font-weight: 700; }
.post-content-inner { font-size: 17px; line-height: 1.9; color: var(--text-main); }
.post-content-inner p { margin-bottom: 22px; }
.post-content-inner h2 { font-size: 26px; font-weight: 800; margin: 35px 0 15px; border-left: 5px solid var(--accent-color); padding-left: 15px; background: linear-gradient(90deg, rgba(255,30,86,0.03), transparent); padding-vertical: 4px; }

.share-container { display: flex; gap: 12px; margin: 35px 0; flex-wrap: wrap; }
.share-btn { padding: 12px 22px; border-radius: 10px; color: #fff; font-size: 14px; font-weight: 800; display: flex; align-items: center; gap: 10px; box-shadow: 0 4px 15px rgba(0,0,0,0.05); }
.share-fb { background: #1877f2; }
.share-tw { background: #1da1f2; }
.share-wa { background: #25d366; }

/*------------------------------------------------------------
HOT TREND NOW FIXED STRUCTURAL MODULE GRID
------------------------------------------------------------*/
.hot-trend-box { margin-top: 45px; background: var(--light-card); border-radius: var(--radius-mega); padding: 32px; box-shadow: var(--shadow-mega); border: 1px solid rgba(0,0,0,0.03); position: relative; }
.hot-trend-box::before { content: ''; position: absolute; top: 0; left: 0; width: 6px; height: 100%; background: var(--primary-gradient); border-radius: 16px 0 0 16px; }
.trend-head { display: flex; align-items: center; gap: 12px; margin-bottom: 24px; }
.trend-head h3 { font-size: 19px; font-weight: 900; background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; text-transform: uppercase; }
.trend-icon-flash { background: var(--primary-gradient); color: #fff; width: 34px; height: 34px; border-radius: 8px; display: flex; align-items: center; justify-content: center; font-size: 15px; box-shadow: var(--neon-glow); }

.trend-grid { display: grid; grid-template-columns: 1fr; gap: 24px; }
@media(min-width: 600px) { .trend-grid { grid-template-columns: 1fr 1fr; } }
.trend-item { display: flex; gap: 16px; align-items: center; background: var(--light-bg); padding: 16px; border-radius: 14px; border: 1px solid rgba(0,0,0,0.02); transition: var(--transition); }
.trend-item:hover { transform: scale(1.03); background: #fff; box-shadow: 0 15px 30px rgba(0,0,0,0.06); border-color: rgba(255, 30, 86, 0.2); }
.trend-img-holder { width: 80px; height: 80px; border-radius: 10px; overflow: hidden; flex-shrink: 0; background: #cbd5e1; }
.trend-img-holder img { width: 100%; height: 100%; object-fit: cover; }
.trend-info h4 { font-size: 14.5px; font-weight: 800; line-height: 1.4; color: var(--text-main); margin-bottom: 6px; }
.trend-meta { font-size: 12px; color: var(--text-muted); font-weight: 700; }

/* Premium Isolated Sidebar Framework */
.sidebar-pane { display: flex; flex-direction: column; gap: 35px; }
.block-widget { background: var(--light-card); padding: 30px; border-radius: var(--radius-mega); box-shadow: var(--shadow-mega); border: 1px solid rgba(0,0,0,0.03); }
.block-title { font-size: 16px; font-weight: 900; text-transform: uppercase; margin-bottom: 24px; position: relative; padding-bottom: 12px; letter-spacing: 0.5px; color: var(--text-main); border-bottom: 2px solid rgba(0,0,0,0.04); }
.block-title::after { content: ''; position: absolute; bottom: -2px; left: 0; width: 50px; height: 2px; background: var(--primary-gradient); }

/* Widget Items Typography Controls */
.search-input-group form { display: flex; gap: 10px; width: 100%; }
.search-field { flex-grow: 1; padding: 14px 18px; border: 1px solid rgba(0,0,0,0.08); border-radius: 12px; background: var(--light-bg); color: var(--text-main); font-weight: 600; outline: none; transition: var(--transition); }
.search-field:focus { border-color: var(--accent-color); background: #fff; box-shadow: 0 0 0 4px rgba(255,30,86,0.1); }
.search-go-btn { background: var(--primary-gradient); color: #fff; border: none; padding: 0 22px; border-radius: 12px; font-weight: 900; cursor: pointer; box-shadow: var(--neon-glow); }

.tag-cloud-list { display: flex; flex-wrap: wrap; gap: 10px; list-style: none; }
.tag-cloud-list li a { display: block; background: var(--light-bg); padding: 8px 16px; font-size: 14px; font-weight: 700; border-radius: 10px; border: 1px solid rgba(0,0,0,0.02); }
.tag-cloud-list li a:hover { background: var(--primary-gradient); color: #fff; transform: translateY(-3px); box-shadow: var(--neon-glow); }

.bio-avatar { width: 95px; height: 95px; border-radius: 50%; margin: 0 auto 15px; border: 4px solid #fff; box-shadow: 0 0 0 3px var(--accent-color); object-fit: cover; display: block; }
.bio-title { font-size: 18px; font-weight: 800; margin-bottom: 8px; text-align: center; }
.bio-desc { font-size: 14px; color: var(--text-muted); line-height: 1.6; text-align: center; margin-bottom: 15px; }
.bio-more-link { display: block; text-align: center; font-size: 13px; font-weight: 800; color: var(--accent-color); text-transform: uppercase; }

/* Heavy Structure Modern Footer */
footer { background: #02050b; color: #94a3b8; padding: 85px 0 40px; margin-top: 90px; border-top: 3px solid rgba(255, 30, 86, 0.25); }
.footer-grid-container { display: grid; grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)); gap: 50px; margin-bottom: 50px; }
.footer-widget-box h3 { color: #fff; margin-bottom: 24px; font-size: 21px; font-weight: 900; position: relative; }
.footer-widget-box h3::after { content: ''; position: absolute; bottom: -8px; left: 0; width: 45px; height: 3px; background: var(--primary-gradient); }
.footer-widget-box p { font-size: 14.5px; line-height: 1.8; }
.footer-links-menu { list-style: none; }
.footer-links-menu li { margin-bottom: 12px; font-size: 14.5px; font-weight: 700; }
.footer-links-menu li a:hover { color: #fff; padding-left: 6px; }

/* Copyright Verification Panel Container */
.footer-legal-base { border-top: 1px solid rgba(255,255,255,0.06); padding-top: 30px; text-align: center; font-size: 14.5px; font-weight: 700; color: #334155; }
.footer-legal-base a { background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; font-weight: 900; }

#back-to-top { position: fixed; bottom: 35px; right: 35px; background: var(--primary-gradient); color: #fff; width: 50px; height: 50px; border-radius: 14px; display: none; align-items: center; justify-content: center; cursor: pointer; z-index: 99999; box-shadow: var(--neon-glow); border: none; transition: var(--transition); }
#back-to-top:hover { transform: translateY(-6px); }

body.script:
//
// 1. Dark Mode State Machine Processor
const themeButtonElement = document.getElementById('dark-mode-engine-btn');
const embeddedIconElement = themeButtonElement.querySelector('i');
themeButtonElement.addEventListener('click', () => {
    document.body.classList.toggle('dark-mode');
    if(document.body.classList.contains('dark-mode')) {
        embeddedIconElement.className = 'fas fa-sun';
    } else {
        embeddedIconElement.className = 'fas fa-moon';
    }
});

// 2. Reading Percentage Vector & Scrolling Element Monitor
window.addEventListener('scroll', () => {
    const documentScrollTop = document.body.scrollTop || document.documentElement.scrollTop;
    const absoluteScrollHeight = document.documentElement.scrollHeight - document.documentElement.clientHeight;
    const progressRatioValue = (documentScrollTop / absoluteScrollHeight) * 100;
    document.getElementById('progress-bar').style.width = progressRatioValue + '%';

    const triggerTopBtn = document.getElementById('back-to-top');
    if(documentScrollTop > 450) { triggerTopBtn.style.display = 'flex'; } else { triggerTopBtn.style.display = 'none'; }
});

document.getElementById('back-to-top').addEventListener('click', () => {
    window.scrollTo({top: 0, behavior: 'smooth'});
});

// 3. Indian Regional Hindi Autonomous Calendar Engine Clock
document.getElementById('live-clock-system').innerText = new Date().toLocaleDateString('hi-IN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
//
